BEGIN;

-- Lorde — Ribs
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$2MvvoeRt8NcOXWESkxWn3g$demosr$, $demosr$Ribs$demosr$, ARRAY[$demosr$Lorde$demosr$]::text[], ARRAY[$demosr$163tK9Wjr9P9DmM0AVK7lm$demosr$]::text[], ARRAY[$demosr$indie pop$demosr$, $demosr$electronic$demosr$, $demosr$pop$demosr$]::text[], $demosr$Pure Heroine$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273187331e276c898d39764cc98$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"reeling through the midnight streets, and never more alone","lens":"a sleepover as a wake","tension":"Mounting Dread","take":"She is grieving her childhood while she is barely out of it, and that is the trick of the whole thing. The setup reads like freedom — a drink spilled, \"Lover's Spit\" left on repeat, her mum and dad letting her stay home. But under every line sits the same low hum: it drives you crazy, getting old. The night out that should feel like a party turns into reeling through the midnight streets with people all around her, and she has never felt more alone. Then the floor opens. I want 'em back, she chants, the minds we had, the thoughts that moved around our heads, mourning a self she has only just lost. So she reaches for the oldest comfort she knows, a friend in the bed beside her like a sleepover, laughing till their ribs get tough. And she already knows the answer before she finishes asking. But that will never be enough.","contradiction":"She climbs into a child's bed with the only friend she needs and knows in the same breath that the closeness can't keep either of them from getting old.","arc":[{"label":"The Stolen Night","mood":"fragile calm","scene":"Her parents let her stay home and the night is hers. A spilled drink, a song on repeat, the feel of being young and unwatched. But the dread is already in the room. It drives you crazy, getting old."},{"label":"The Dream Sours","mood":"lonely panic","scene":"The same night turns. She's reeling through the midnight streets with a crowd around her and can't feel a single one of them. This dream isn't feeling sweet anymore. It feels so scary, getting old."},{"label":"The Mourning","mood":"open grief","scene":"The dread cracks into full grief. I want 'em back, she repeats, the minds we had, the thoughts that moved around our heads. She is at a funeral for a childhood self who isn't even cold yet, and it's not enough to feel the lack."},{"label":"The Clinging","mood":"tender, doomed","scene":"She reaches for the one thing left. A friend in the bed beside her like little kids, laughing till their ribs get tough. The comfort is real and she holds it close. But that will never be enough, over and over, until the night runs out."}],"lines":[{"line":"It drives you crazy, getting old"},{"line":"And I've never felt more alone"},{"line":"I want 'em back, I want 'em back\nThe minds we had, the minds we had"},{"line":"Sharing beds like little kids"},{"line":"But that will never be enough"}],"texture":"A hushed, half-acoustic pulse opens it, sparse enough to hear the room, then the voice stacks on itself and swirls into an echo that keeps swelling. The tempo sits up near a dance beat, but the mood underneath is almost without color, so the swell never lifts you. It just circles, a party that keeps spinning and never warms."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
FROM public.song s
WHERE s.spotify_id = $demosr$2MvvoeRt8NcOXWESkxWn3g$demosr$
  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

-- Dua Lipa — Houdini
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$4OMJGnvZfDvsePyCwRGO7X$demosr$, $demosr$Houdini$demosr$, ARRAY[$demosr$Dua Lipa$demosr$]::text[], ARRAY[$demosr$6M2wZ9GZgrQXHCFfjv46we$demosr$]::text[], ARRAY[$demosr$pop$demosr$, $demosr$dance-pop$demosr$, $demosr$disco$demosr$]::text[], $demosr$Radical Optimism$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273001d5706fddc72561f6488af$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"a kiss blown across the room, already halfway out the door","lens":"a vanishing act as a dare","tension":"Daring Hope","take":"A vanishing act, run as a dare. She tells you up front she comes and goes and isn't here for long, so the disappearing is the terms of the deal and not the tragedy. Catch me or I go Houdini — the threat doubles as the invitation. She keeps raising the bar on you: prove you've got the right to please her, practice what you preach, give her something that'll make her believe. It plays like a woman who can't be held, right up until the post-chorus lets the other thing slip out. Maybe you could cause a girl to change her ways. Maybe you could be the one to make me stay. The whole escape trick was a test someone was supposed to pass.","contradiction":"She bills herself as the one who always slips the cuffs and spends the entire time hoping you're good enough to make the trick fail.","arc":[{"label":"The Dare","mood":"Confident, teasing","scene":"She lays out the rules like a magician naming the trick before it starts. She comes and she goes, she's not here for long, and the only way to keep her is to catch her. The exit stays open on purpose. She's daring you to be the reason she doesn't take it."},{"label":"The Test","mood":"Demanding, skeptical","scene":"Now she's raising the bar. Everything you say sounds sweet, but she wants to know if you practice what you preach. Prove you've got the right to please her. The sweetness isn't enough on its own. She needs something that'll make her believe."},{"label":"The Tell","mood":"Hopeful, exposed","scene":"The game cracks for a second. If you're good enough, you'll find the way, and maybe you could cause a girl to change her ways. Under all the coming and going is the line she almost doesn't want to say out loud. Maybe you could be the one to make me stay."}],"lines":[{"line":"Catch me or I go Houdini"},{"line":"Prove you got the right to please me"},{"line":"But do you practise everything that you preach?"},{"line":"Maybe you could be the one to make me stay"}],"texture":null}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
