WHERE s.spotify_id = $demosr$4OMJGnvZfDvsePyCwRGO7X$demosr$
  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

-- Frank Ocean — Thinkin Bout You
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$7DfFc7a6Rwfi3YQMRbDMau$demosr$, $demosr$Thinkin Bout You$demosr$, ARRAY[$demosr$Frank Ocean$demosr$]::text[], ARRAY[$demosr$2h93pZq0e7k5yf4dywlkpM$demosr$]::text[], ARRAY[$demosr$neo-soul$demosr$, $demosr$rnb$demosr$, $demosr$soul$demosr$]::text[], $demosr$channel ORANGE$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b2737aede4855f6d0d738012e2e5$demosr$, now(), now())
