INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"rain indoors in a place it never rains","lens":"denial into confession","tension":"Masked Longing","take":"He keeps insisting he doesn't love you, and every line around the denial proves it false. \"No, I don't like you.\" \"Since you think I don't love you.\" The brags pile up absurd — a beach house in Idaho, a fighter jet he never gets to fly — because deflection is easier than the question underneath: do you think about me still. The tears he won't call tears pour anyway. Then the act drops. Yes, of course he remembers. You were his first time, a new feel that won't get old in his soul. Forever is the word he can't stop circling, and he still doesn't know if you've thought that far ahead.","contradiction":"He swears he never loved you and in the same breath needs you to remember you were his first.","arc":[{"label":"The Flood He Won't Name","mood":"Grief, denied","scene":"A tornado wrecked the room before you came, and now he's asking you to excuse the mess. It doesn't rain in Southern California. His eyes don't shed tears either. They pour anyway."},{"label":"Reaching For Forever","mood":"Aching hope","scene":"Thinking about you is all he does, and he wants to know if it runs both ways. Do you think about me still. He's already landed on forever. He has no idea if you've thought past tonight."},{"label":"Playing It Cool","mood":"Guarded deflection","scene":"Now he plays it cool. No, he doesn't like you, he just thought you were cute enough to kiss. The lies get bigger to sell it — a beach house, a fighter jet — and not one of them covers the want underneath."},{"label":"The Mask Off","mood":"Tender confession","scene":"The act finally drops. Yes, of course he remembers how you felt. You were his first time, his first love, a new feel he swears won't ever get old. He'll ride this road with you until it turns from color to black and white."}],"lines":[{"line":"A tornado flew around my room before you came"},{"line":"My eyes don't shed tears, but boy, they pour"},{"line":"'Cause I been thinkin' 'bout forever, ooh"},{"line":"No, I don't like you, I just thought you were cool enough to kick it"},{"line":"You know you were my first time"}],"texture":"Hushed and sparse, the vocal sitting right up front with almost nothing behind it. There's a soft groove your body wants to follow, but the low light and lower mood keep it sunk in blue."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
