-- Phoebe Bridgers — Motion Sickness
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$5xo8RrjJ9CVNrtRg2S3B1R$demosr$, $demosr$Motion Sickness$demosr$, ARRAY[$demosr$Phoebe Bridgers$demosr$]::text[], ARRAY[$demosr$1r1uxoy19fzMxunt3ONAkG$demosr$]::text[], ARRAY[$demosr$indie folk$demosr$, $demosr$singer-songwriter$demosr$, $demosr$indie$demosr$]::text[], $demosr$Stranger in the Alps$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b27368b90c3b34c3ac22856ddab8$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"somebody roll the windows down","lens":"a toxic love as motion sickness","tension":"Reeling Heartache","take":"The pun is the wound. The man this is about had Ménière's disease, an illness that feels exactly like motion sickness, and now that sickness is hers — the dizzy, can't-find-the-floor nausea of loving someone who hurt her. She hates him and misses him like a little kid and can hardly feel anything, all true in the same breath. From outside the glass she sees him plainly now. He's throwing rocks around his own room and bleeding on the floor, and she's glad she got out even as she's sorry for how it ended. The bridge says the quiet part out loud: he was bored when he met her, and he was in a band when she was born. By the end the fight changes shape. 'No words I could scream' becomes 'I will try to drown you out,' and then the question she can't shake — what would happen if she surrendered to the sound.","contradiction":"She wants to scream him out of her head and wonders, in the same breath, what would happen if she surrendered to the sound instead.","arc":[{"label":"The Split Feeling","mood":"numb, contradictory","scene":"She hates him for what he did and misses him like a little kid, both at once and neither one winning. She says she faked it the whole time and that it's fine, because she can hardly feel anything now anyway. The numbness is the wound, not the cure."},{"label":"The Nausea","mood":"queasy, trapped","scene":"The sickness has a name now. Emotional motion sickness, the kind that needs the windows rolled down for air. There are no words in English she could scream loud enough to drown him out, and his voice follows her everywhere she goes."},{"label":"Outside the Glass","mood":"clear-eyed, cold","scene":"From outside the glass she finally sees him for what he is. He's throwing rocks around his own room and bleeding on his back in the broken glass, and she's glad she made it out even as she's sorry it went down like it did. Then the math lands cold. He was bored when he met her, and he was in a band when she was born."},{"label":"Surrender to the Sound","mood":"tentative, releasing","scene":"Something shifts. The voice that had no words to scream now says she will try to drown him out — she's done staying quiet about it. And then the strangest pull of all takes hold. She wants to know what would happen if she stopped fighting and gave herself over to the sound."}],"lines":[{"line":"I hate you for what you did\nAnd I miss you like a little kid"},{"line":"I have emotional motion sickness"},{"line":"And you, you were in a band when I was born"},{"line":"I wanna know what would happen\nIf I surrender to the sound"}],"texture":"Warm, mid-tempo acoustic strum, indie folk that nearly sounds content with itself. That brightness sits right on top of words about nausea and a man she can't scream out of her head."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
