VALUES ($demosr$3HMY0r2BAdpasXMY8rseR0$demosr$, $demosr$Too Sweet$demosr$, ARRAY[$demosr$Hozier$demosr$]::text[], ARRAY[$demosr$2FXC3k01G6Gw61bmprjgqS$demosr$]::text[], ARRAY[$demosr$folk$demosr$, $demosr$blues$demosr$, $demosr$rock$demosr$]::text[], $demosr$Unheard$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273be392334d99f82bc410cb239$demosr$, now(), now())
