INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"dark as a lake, smelling like a bonfire, lost in a haze","lens":"a breakup phrased as a drink order","tension":"Wry Resignation","take":"A breakup phrased as a drink order. She lives clean, early to bed and up for the sunrise, her mouth treated like Heaven's gate and the rest of her policed like the TSA. He can't meet her there and doesn't want to. So he answers every plea to live right with his order: whiskey neat, coffee black, bed at 3. Each one is the unsweetened version of itself, and he likes it bitter. \"You're too sweet for me\" arrives as compliment and verdict in the same breath. Then comes the gentlest cruelty of all. He tells her she's a grape worth turning into wine, and if she'll just sit in a barrel and go bitter, maybe he'll wait. Which is no wait at all.","contradiction":"He'd wait for her to turn as bitter as the whiskey he loves, knowing the sweetness that draws him is exactly what the turning would destroy.","arc":[{"label":"The Mismatch","mood":"bemused, envious","scene":"He surfaces at 10 and doesn't say a word before then, while she's already up for the sunrise. He genuinely can't fathom how she sleeps so well or lives so right. Half of him suspects the discipline is a performance she puts on for others. The other half just envies that she can do it at all."},{"label":"The Order","mood":"warm, immovable","scene":"She keeps telling him to go to bed before the daylight, and he answers with a list of his vices stated flat as preferences. Whiskey neat. Coffee black. Bed at 3. \"You're too sweet for me\" is the kindest possible no, and he means every word of both the kindness and the no."},{"label":"The Barrel","mood":"fond, withholding","scene":"He softens, calls her bright as the morning and soft as the rain, pretty as a vine. The affection is real and he overrides it anyway. If she can sit in a barrel and ferment into something jaded and bitter, maybe then he'll wait. He wants the grape gone before he'll keep the wine."}],"lines":[{"line":"How do you sleep so well?"},{"line":"I think I'll take my whiskey neat\nMy coffee black and my bed at 3"},{"line":"You're too sweet for me"},{"line":"You treat your mouth as if it's Heaven's gate\nThe rest of you like you're the TSA"},{"line":"If you can sit in a barrel, maybe I'll wait"}],"texture":"A bright, bouncing blues-rock groove, electric and loud and built to move your shoulders. It's the sunniest possible delivery for a man ordering everything bitter and undiluted."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
