WHERE s.spotify_id = $demosr$3HMY0r2BAdpasXMY8rseR0$demosr$
  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

-- Arctic Monkeys — Do I Wanna Know?
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$5FVd6KXrgO9B3JPmC8OPst$demosr$, $demosr$Do I Wanna Know?$demosr$, ARRAY[$demosr$Arctic Monkeys$demosr$]::text[], ARRAY[$demosr$7Ln80lUS6He07XvHI8qqHH$demosr$]::text[], ARRAY[$demosr$indie rock$demosr$, $demosr$rock$demosr$, $demosr$indie$demosr$]::text[], $demosr$AM$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b2734ae1c4c5c45aabe565499163$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"that tune on repeat, drinks spilling on the settee","lens":"an interrogation as a confession","tension":"Helpless Longing","take":"Every question he aims at you lands back on him. The blush, the secrets, the aces up your sleeve — he sounds like he's reading you, but he's the one exposed, dreaming of you every night this week and playing that tune until he passes out drinking alone. The questions are cover for a confession he can't make straight. Then he says the real fear out loud: do I wanna know if this feeling flows both ways. He'd rather not know, because an answer could finish him. By the time he's crawling back the cover is gone, and he admits he's too busy being yours to fall for anybody new. And the last thing he asks is whether you even want him crawling back at all.","contradiction":"He fires off question after question to find out if she still wants him, and builds the whole asking around not wanting the answer.","arc":[{"label":"The Cool Inquisition","mood":"feigned composure","scene":"He plays it casual and fires the questions like he holds the cards. Have you got colour in your cheeks, are there aces up your sleeve. Underneath, he's the one who's dreamt about you nearly every night and can't shake the tune that makes him think of you."},{"label":"The Admission","mood":"anxious, exposed","scene":"The pose slips and the real fear comes out. He was sorta hoping you'd stay. He half-knows the nights were only made for saying things you both take back the next day, and he can't decide if he even wants to know whether it flows both ways."},{"label":"The Crawl","mood":"helpless surrender","scene":"No more disguise now. He's crawling back to you, calling when he's had a few because he always does. He's thought it through and the conclusion is the same one he started with. Too busy being yours to fall for anyone new."},{"label":"The Last Doubt","mood":"insecure, unresolved","scene":"Even surrender doesn't settle it. He's coming back regardless, but the final question isn't whether he'll crawl. It's whether you want him to, and he never gets that answer."}],"lines":[{"line":"Have you got colour in your cheeks?"},{"line":"I've dreamt about you nearly every night this week"},{"line":"(Do I wanna know) If this feelin' flows both ways?"},{"line":"Simmer down an' pucker up, I'm sorry to interrupt"},{"line":"Do you want me crawlin' back to you?"}],"texture":"A slow electric-guitar groove that prowls at a near-resting pulse, all swagger and restraint. The cool of it sits right on top of a man on his knees."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
