VALUES ($demosr$1Qrg8KqiBpW07V7PNxwwwL$demosr$, $demosr$Kill Bill$demosr$, ARRAY[$demosr$SZA$demosr$]::text[], ARRAY[$demosr$7tYKF4w9nC0nq9CsPZTHyP$demosr$]::text[], ARRAY[$demosr$trap$demosr$, $demosr$rnb$demosr$, $demosr$pop$demosr$]::text[], $demosr$SOS$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273c5276ed6cb0287df8d9be07f$demosr$, now(), now())
