INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"the basement, planning a home invasion in a sweet, even voice","lens":"love as a home invasion","tension":"Sweet Desperation","take":"The love she keeps swearing to is the thing breaking into his house. She frames all of it as growth. She's so mature, she got a therapist to remind her there are other men, she's still a fan even though she was salty. None of it takes. What she actually wants is simple and total: if she can't have him, no one should. By the end the jealousy isn't even about him. It's about the alone. She'd rather be in jail than face an empty room, and by the last chorus she'd rather be in Hell. She did it all for love, sober, with no drugs to blame, and she says it smiling.","contradiction":"She has the therapist telling her there are other men, and she still decides no one else gets to have him.","arc":[{"label":"The Mature Mask","mood":"sweet, simmering","scene":"She swears she's over it. She's still a fan, she was only a little salty, she's so mature about the whole thing. But she can't stand the sight of him happy with someone else, not while she isn't the one driving."},{"label":"The Plan","mood":"calm, chilling","scene":"The mask slips into a plan. She clocks him at the farmer's market with his perfect peach, out of reach. So she heads down to the basement. The text will be evidence and she knows it. Now he's face-down on the floor."},{"label":"The Justification","mood":"serene, devoted","scene":"She wants you to understand she meant it. No drugs, no crime of passion, fully sober. She did it all for love, and she says that like it settles everything."},{"label":"The Deed Done","mood":"doomed, content","scene":"The fantasy turns past tense. She just killed her ex, oops, his girlfriend next, he left her no choice. And she'd still rather be in Hell than spend one night alone."}],"lines":[{"line":"Hate to see you happy if I'm not the one drivin'"},{"line":"His new girlfriend's next, how'd I get here?"},{"line":"You was at the farmer's market with your perfect peach"},{"line":"Now you layin' face-down, got me singin' over a beat"},{"line":"I did all of this sober"}],"texture":"A soft, sing-song R&B melody rides an unbothered mid-tempo trap beat, her voice gentle and a little bored. The sweetness is the trick, carrying a double-murder confession like it weighs nothing."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
