-- Kendrick Lamar — Not Like Us
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$6AI3ezQ4o3HUoP6Dhudph3$demosr$, $demosr$Not Like Us$demosr$, ARRAY[$demosr$Kendrick Lamar$demosr$]::text[], ARRAY[$demosr$2YZyLoL8N0Wb9xBt1NhZWg$demosr$]::text[], ARRAY[$demosr$trap$demosr$, $demosr$hip-hop$demosr$, $demosr$rap$demosr$]::text[], NULL, $demosr$https://i.scdn.co/image/ab67616d0000b2731ea0c62b2339cbf493a999ad$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"a packed floor stepping in time to a guilty verdict","lens":"a sentencing as a block party","tension":"Gleeful Contempt","take":"The kill is the party. Kendrick takes the heaviest charges he can level — pedophile, colonizer, fraud — and sets them to a beat made for a packed floor. That is the move Drake never saw coming. Everyone expected the club-ready diss to come from the other side. Instead the jabs land in flurries, 'wop, wop, wop,' and then he draws the line clean: they not like us. By the third verse it stops being about two rappers at all. Drake becomes the man who runs to Atlanta for a check and a borrowed accent, a colonizer of a culture that was never his. The verdict goes from personal to historical without slowing down. By the end it is pure call-and-response. Step this way, step that way. An execution you can two-step to.","contradiction":"Every accusation gets harder to deny and easier to chant in the same breath.","arc":[{"label":"The Flurry","mood":"Gleeful, merciless","scene":"A ghost-story whisper opens it, and then the jabs come fast. He names Drake a free throw, a boogeyman of his own making, a man who likes them young. Each bar lands like a punch thrown before you can lift a hand to block it. No setup, no mercy."},{"label":"The Line","mood":"Cold certainty","scene":"Three words, over and over. They not like us. The room splits down the middle and the gap between the two sides is the whole point. Everyone in earshot is already standing on one of them."},{"label":"The Widening","mood":"Righteous fury","scene":"Once upon a time all of us was in chains. Now the fight is bigger than two rappers trading shots. Drake becomes the tourist who flies into Atlanta for a check and a few dollars of borrowed credibility, a colleague turned colonizer. The insult turns into history."},{"label":"The Two-Step","mood":"Triumphant, dancing","scene":"By the end the kill is a dance. Are you my friend? Are we locked in? Step this way, step that way. The destruction is total and your feet are moving to it."}],"lines":[{"line":"Tryna strike a chord and it's probably A minor"},{"line":"Certified Lover Boy? Certified pedophiles"},{"line":"They not like us, they not like us, they not like us"},{"line":"No, you not a colleague, you a fuckin' colonizer"},{"line":"Then step this way, step that way"}],"texture":"A spare, bouncing West Coast beat at a walking tempo, low on energy and built entirely for the floor. It sounds like a block party, and that is the trick, because the words riding it read like an indictment."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
