VALUES ($demosr$6tNQ70jh4OwmPGpYy6R2o9$demosr$, $demosr$Beautiful Things$demosr$, ARRAY[$demosr$Benson Boone$demosr$]::text[], ARRAY[$demosr$22wbnEMDvgVIAGdFeek6ET$demosr$]::text[], ARRAY[$demosr$pop rock$demosr$, $demosr$power pop$demosr$]::text[], $demosr$Fireworks & Rollerblades$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273bef221ea02a821e7feeda9cf$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"her asleep in his arms while he lies awake in the dark","lens":"a blessing as a loan that comes due","tension":"Grateful Dread","take":"Every good thing he names is a thing he's already afraid of losing. He starts by counting how far he's come — better than the last four cold Decembers, a girl his parents love, family every month, peace, love, faith coming back. Then the Job line lands and undoes all of it: the things God gives, God can take away. So the gratitude curdles in the same breath it's spoken. Holding her every night is a feeling he wants to get used to, and the wanting is the problem, because there's no man as terrified as the man who stands to lose you. He even hears himself doing it — if everything's good and it's great, why does he sit and wait 'til it's gone? He can't answer, so he just keeps up the prayer. Please stay. Don't take these beautiful things that I've got.","contradiction":"He thanks God for the girl He sent and begs God not to take her back, and it's the same prayer either way.","arc":[{"label":"The Good Years","mood":"warm relief","scene":"After a rough stretch, the floor finally feels solid. He's doing better than four cold Decembers ago, he sees his family, and he found a girl his parents took to. For a second he lets himself think he might have it all."},{"label":"The Flinch","mood":"dawning dread","scene":"The same God he thanks for her is the God who can take her away. That thought turns holding her at night from comfort into stakes. Nobody is more terrified than the man with everything to lose, and now that's him."},{"label":"The Question","mood":"anxious self-awareness","scene":"He catches himself doing it. He's got peace, he's got love, his faith is coming back — and still he sits up waiting for it to vanish. If everything's good, why does he keep bracing for the end? He has no answer."},{"label":"The Prayer","mood":"open begging","scene":"All of it collapses into one plea, repeated until it's the whole song. Please stay. I want you, I need you, oh God, don't take. The need outlasts the gratitude, and the last word he leaves you on is don't take."}],"lines":[{"line":"But I know the things He gives me, He can take away"},{"line":"But there's no man as terrified as the man who stands to lose you"},{"line":"I want you, I need you, oh God\nDon't take\nThese beautiful things that I've got"},{"line":"If everything's good and it's great, why do I sit and wait 'til it's gone?"},{"line":"I've got peace and I've got love\nBut I'm up at night thinkin' I just might lose it all"}],"texture":"It opens low and close, then lifts into a big power-pop swell with that high, cracking belt at the top of his range, the kind of release built to read as triumph. Every word underneath it is bracing for the loss."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
