ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"'til the light leaves my eyes","lens":"measuring love against the grave","tension":"Tender Ache","take":"Every measure of how big this love is comes back as a measure of death. She can't say it plainly, so she says it in graves: stay till I rot, till I'm in the casket you carry, till the light leaves my eyes. The forever is real and the doubt is real at the same moment. Might not be forever, but if it's forever, it's even better. Then it turns outward toward someone who can't believe any of it, whose mind is polluted with reasons they aren't worth loving, and she gets blunt about it. You're so full of shit, don't be stupid, don't you dare quit. By the end she's reaching back before this life even started. I knew you in another life. I love you, don't act so surprised.","contradiction":"She swears she'll love you until the light leaves her eyes and admits in the same breath that it might not last.","arc":[{"label":"The Grave Clause","mood":"clinging, tender","scene":"She asks you to stay, then keeps stretching the ask past anything reasonable. Till the grave. Till the casket you carry. If you go, she's going too. The voice stays gentle, but the size of what she's asking is total."},{"label":"If It's Forever","mood":"hopeful surrender","scene":"Here she lets the doubt in and loves anyway. She can't change the weather and it might not last, so she stops fighting that. She just adds that if it does last, even better. The surrender comes out sounding like contentment."},{"label":"Don't Be Stupid","mood":"loving frustration","scene":"The whole thing swings toward you, the one who won't keep a single compliment and keeps calling it a bit. Your mind is polluted with every reason you can't be loved. She refuses all of it flat. You're full of shit, don't be stupid, don't quit on this."},{"label":"Another Life","mood":"certain, settled","scene":"She places the love before this life even began. The same look in your eyes from somewhere she half-remembers. I love you, don't act so surprised, and the whole song folds down into the one plain thing it kept circling."}],"lines":[{"line":"I want you to stay\n'Til I'm in the grave"},{"line":"And if I'm turnin' blue, please don't save me"},{"line":"Birds of a feather, we should stick together, I know"},{"line":"Say you don't see it, your mind's polluted"},{"line":"I knew you in another life\nYou had that same look in your eyes"}],"texture":"A soft, mid-tempo sway pitched low and close, more bedroom hush than big pop, the kind of groove you rock back and forth to without thinking. The warmth of it never lifts above a murmur, and the words it carries are funeral vows."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
