INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"crying through the suburbs, driving home to a house that isn't yours anymore","lens":"the open road as a dead end","tension":"Disbelieving Grief","take":"The license was supposed to be the two of you. He taught her to drive, he was excited for her, the whole point was the day she'd finally pull up to his house. So she gets the keys, the freedom to go anywhere, and the only place anywhere leads is past his street. That's the cruelty of it. The milestone they planned together arrives and he isn't there for it, and now every road just loops her back toward him. She can't square it. She felt this for no one, ever, and somehow he's fine, blonde girl and all, so okay now that she's gone. He even wrote her a forever into a song and didn't mean a word. By the bridge the freedom is just a car she sits in alone, seeing his face in every white one, still loving him out loud past the place they're through.","contradiction":"She finally has the keys to drive anywhere, and the only place she ever ends up is alone outside the house of someone who's perfectly fine without her.","arc":[{"label":"The Earned Milestone","mood":"Hollow Ache","scene":"She got the license they always talked about, the one he was so excited for, the one that was supposed to end at his front door. Instead she's driving the suburbs alone and crying, because the day finally came and he isn't in it."},{"label":"He's Okay, She Isn't","mood":"Disbelieving Hurt","scene":"There's a blonde girl now, older, everything she's insecure about. What guts her isn't the girl. It's how easily he moved on, how he could be so okay now that she's gone, while she can't imagine ever loving anyone else."},{"label":"The Breakdown","mood":"Raw Longing","scene":"Red lights, stop signs, his face in every white car and front yard. She can't drive past the old places. The composure drops and she just says it, twice, swearing through tears that she still loves him even knowing they're through."}],"lines":[{"line":"I got my driver's license last week\nJust like we always talked about"},{"line":"She's so much older than me\nShe's everything I'm insecure about"},{"line":"And I just can't imagine how you could be so okay now that I'm gone"},{"line":"'Cause I still fuckin' love you, babe"},{"line":"'Cause you said forever, now I drive alone past your street"}],"texture":null}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
