ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"black lights and a mirrored disco ball, a line outside the door","lens":"a stage as the home she chose","tension":"Defiant Joy","take":"Home isn't a place she's returning to here. It's a stage in heels she had to leave Tennessee to find. The pull starts as fantasy, those crazy visions of L.A. she can't ignore, and the cost is named flat: it won't make mama proud, it's gonna cause a scene. Then the night actually arrives. Jaws hit the floor, lovers crowd the bathroom, and every reason to have left it all keeps proving itself right. You can hear the turn in one word. The wicked dreams she was once just having become the wicked dreams she now thanks. And the mother never goes quiet. A thousand miles away her Southern drawl still asks God what have you done, still calls her a pink pony girl like a verdict. The answer isn't an argument. She's just gonna keep on dancing.","contradiction":"She still loves Tennessee and her mother and carries the drawl with her, and she's never going back.","arc":[{"label":"The Pull","mood":"restless yearning","scene":"Her mother wants her to stay, and she can't ignore the visions of herself in L.A. where boys and girls can all be queens. She already knows what it costs. The scene she'll cause, the scream when mama sees her baby girl, all of it priced and accepted before she's even gone."},{"label":"The Landing","mood":"triumphant belonging","scene":"On the stage in her heels, this is where she belongs. Black lights, a mirrored disco ball, a line out the door, and every night hands her another reason she was right to leave it all. The dream she was only having a year ago is a dream she now thanks out loud."},{"label":"The Drawl","mood":"tender defiance","scene":"She hasn't left them behind. Every Saturday she can hear her mother's Southern drawl a thousand miles away, still horrified, still asking what she's done. She loves them and Tennessee and won't soften the answer one inch. She's gonna keep on dancing."}],"lines":[{"line":"But I can't ignore the crazy visions of me in L.A."},{"line":"Won't make my mama proud, it's gonna cause a scene"},{"line":"On the stage in my heels, it's where I belong, down at the"},{"line":"I thank my wicked dreams, a year from Tennessee"},{"line":"I can hear your Southern drawl a thousand miles away, saying"}],"texture":"A mid-tempo synth-pop pulse, bright and built for the floor without ever racing. The valence sits right at the middle, so the euphoria never quite outruns the homesick ache underneath it."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
