-- Tyler, the Creator — EARFQUAKE
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$5hVghJ4KaYES3BFUATCYn0$demosr$, $demosr$EARFQUAKE$demosr$, ARRAY[$demosr$Tyler, the Creator$demosr$]::text[], ARRAY[$demosr$4V8LLVI7PbaPR0K2TGSxFF$demosr$]::text[], ARRAY[$demosr$rock$demosr$, $demosr$pop$demosr$, $demosr$alternative$demosr$]::text[], $demosr$IGOR$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b27330a635de2bb0caa4e26f6abb$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"riding around, your love be shakin' me up","lens":"claiming the fault before it quakes","tension":"Trembling Need","take":"He's already taken the blame before there's even a fight. Before she's said she's going, he's down on the floor with \"don't leave, it's my fault,\" claiming the crack in the ground as his own so she has no reason to walk. The earthquake is her love and it's already shaking him loose, and the note nails the double meaning. A fault is the fault line where the crust splits, and he's standing right on it, calling it his. He doesn't want confrontation or conversation or side information. He just needs confirmation she still feels it. Even Carti's verse, all D-Rose and diamonds that aren't Tiffany, can't hold its own swagger and slides into \"so in love, so in love.\" By the end he's counting it down like a vow he has to keep, then the word snaps off mid-breath: \"I'll need—.\"","contradiction":"He swears the whole collapse is his fault, and in the same breath says he'll need her to survive the collapse.","arc":[{"label":"The Vow","mood":"Desperate, bracing","scene":"Before a single love line, he's already promising himself he won't blow it. \"For real, for real this time,\" said so many times it sounds less like confidence than a man talking himself off a ledge. \"Bitch, I cannot fall short.\" The stakes are set before we even know who she is."},{"label":"The Plea","mood":"Pleading, shaken","scene":"The ground gives out. Her love shakes him up and breaks his heart in the same motion, and his answer is to take all of it on himself. \"Don't leave, it's my fault.\" He's not defending himself. He's removing every reason she might have to go, including his own dignity."},{"label":"The Flex That Folds","mood":"Strutting, then soft","scene":"Carti struts in with the bravado the chorus can't afford, diamonds that aren't Tiffany and a girl as wild as Woah Vicky. None of it holds. The whole performance melts down into the same admission underneath everything: \"so in love, so in love.\""},{"label":"The Unfinished Need","mood":"Anxious, breaking off","scene":"Stripped of confrontation and conversation, all he wants is to know what's happening, for real. He counts the apology down like he can will it to land, \"one, two, three,\" and then the need itself can't make it out whole. \"Don't, do-do-do-do-do, I'll need—.\""}],"lines":[{"line":"Bitch, I cannot fall short"},{"line":"Don't leave, it's my fault"},{"line":"So in love (I been so in love)"},{"line":"Don't, do-do-do-do-do, I'll need—"}],"texture":"A slow soul sway near 80 BPM, the room around it open and live-sounding, gospel-warm backing voices cushioning every line. The sound is soft and comforting, completely at odds with the man inside it who can't stop saying it's his fault."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
