INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"sin city cold and empty, no one around to call","lens":"her touch as the fix","tension":"Frantic Longing","take":"Every craving in here is the same craving wearing two faces. He's going through withdrawals and he needs her touch, and the song never lets those two needs separate — the body that lights up at the slightest contact is the body coming off the drug, sensitive to everything. So he's been trying to call from inside a Vegas that's gone cold on him, blinded by lights that are the city and the flashing car all at once. He can't sleep until he feels her, can't see clearly when she's gone. When the sun comes up he's out of time, so he hits the road in overdrive to reach the one person he trusts when he's like this. He's coming back to say the thing he could never say on the phone. He just can't ever quite say it.","contradiction":"He's been trying to call her this whole time, and the one thing he came back to tell her is the thing he could never say on the phone.","arc":[{"label":"The Call That Won't Connect","mood":"vulnerable, aching","scene":"He's been on his own long enough, and he says it like a man admitting a wound. He needs her to show him how to love. The withdrawal is talking, and her touch is the only thing that registers."},{"label":"The Empty City","mood":"numb, drowning","scene":"Sin City is cold and empty around him, and no one's left to judge what he does in it. He's blinded by the lights and drowning in the night. Without her he can't see straight, and he can't sleep until he feels her hand."},{"label":"Overdrive","mood":"desperate, racing","scene":"The sun comes up and the night runs out on him. He hits the road in overdrive, too fast, like reaching her in time is the only thing that matters. The same craving, now in motion."},{"label":"The Thing He Can't Say","mood":"raw, halting","scene":"He's just coming back to let her know. He could never say it on the phone, and this time he swears he'll never let her go. The biggest thing he feels is still the thing his mouth won't carry."}],"lines":[{"line":"I've been on my own for long enough"},{"line":"You can turn me on with just a touch, baby"},{"line":"Sin City's cold and empty"},{"line":"So I hit the road in overdrive, baby, oh"},{"line":"I could never say it on the phone"}],"texture":"A bright 80s synth pulse at a sprinter's tempo, all neon glide and forward motion, the kind of sound built for a clean getaway. The valence underneath sits low and dark, so the glow keeps racing while the man inside it stays cold and emptied out."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
FROM public.song s
