-- Harry Styles — As It Was
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$4Dvkj6JhhA12EX05fT7y2e$demosr$, $demosr$As It Was$demosr$, ARRAY[$demosr$Harry Styles$demosr$]::text[], ARRAY[$demosr$6KImCVD70vtIoJWnq6nGn3$demosr$]::text[], ARRAY[$demosr$pop$demosr$, $demosr$pop rock$demosr$, $demosr$synthpop$demosr$]::text[], $demosr$Harry's House$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b27382ce362511fb3d9dda6578ee$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"alone on the floor, the phone still ringing","lens":"the way it was as a goodnight","tension":"Restless Grief","take":"Everyone who loves you can only reach you through a phone. A goddaughter leaves a voicemail to say goodnight. A worried voice asks why you're sitting at home on the floor and what pills you're on. Your father lives by himself and just wants to know you're well. The promise keeps coming — 'in this world, it's just us' — but every scene is one person alone, calling another. You ring the bell and nobody comes. Under all the rush it's the same quiet fact each time: it's not the same as it was, and there's no way back. So he won't say it out loud. 'I don't wanna talk about the way that it was.'","contradiction":"He sings 'in this world, it's just us' from the floor, with no one in the room and only a ringing phone for company.","arc":[{"label":"The Reach","mood":"tender, weighted","scene":"Gravity holds him back and still he asks you to hold out the palm of your hand. A child's voicemail floats in to say goodnight. Something in him is reaching for one warm hand in the room."},{"label":"Not the Same","mood":"bright, grieving","scene":"Then the realization lands and it won't lift. Whatever this is now, it's not the same as it was, and it's never going back. He says it twice, three times, like saying it might make it less true."},{"label":"Nobody Coming","mood":"isolated, shut","scene":"Now it's just him on the floor, a worried voice on the line asking what pills he's on. He rings the bell and nobody comes. His father lives alone too and just wants word that he's well, and the only answer he gives the whole world is that he doesn't want to talk about the way it was."}],"lines":[{"line":"I want you to hold out the palm of your hand"},{"line":"You know it's not the same as it was"},{"line":"What kind of pills are you on?"},{"line":"Your daddy lives by himself"}],"texture":"A bright synth pulse running fast and weightless, the kind of sound built for windows-down summer. Every line it carries is about being alone on the floor."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
