  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

-- Sabrina Carpenter — Manchild
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$42UBPzRMh5yyz0EDPr6fr1$demosr$, $demosr$Manchild$demosr$, ARRAY[$demosr$Sabrina Carpenter$demosr$]::text[], ARRAY[$demosr$74KM79TiuVKeVCqs8QtB0B$demosr$]::text[], ARRAY[$demosr$pop$demosr$, $demosr$dance-pop$demosr$, $demosr$indie pop$demosr$]::text[], $demosr$Man's Best Friend$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273062c6573009fdebd43de443b$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"won't you let an innocent woman be","lens":"a takedown as self-portrait","tension":"Mocking Exasperation","take":"She spends the whole thing roasting him and barely breaks a sweat doing it. The phone that wasn't broken, just uncharged. The outfit she prays is ironic. \"Did you just say you're finished? Didn't know we started.\" Each line is a clean hit, and she keeps posing as the put-upon innocent woman who never signed up for any of this. Then the bridge turns the knife on her own hand. She likes her men incompetent. She likes her boys playing hard to get. And right after admitting it, she swears \"they choose me, I'm not choosing them\" — the denial too quick to believe. The portrait she's been drawing of him turns out to be a mirror, and \"amen, hey, men\" is half blessing, half surrender to the type she keeps going back to.","contradiction":"She calls herself an innocent woman dragged into this and admits in the same breath that incompetent is exactly her type.","arc":[{"label":"The Roast","mood":"sharp, amused","scene":"She's got the receipts and she's enjoying them. The dead phone, the outfit, the boy who announced he was finished before anything began. She names what's wrong with him and barely raises her voice, because there's a cuter word for it and she already knows what it is."},{"label":"The Innocent Act","mood":"mock-weary, theatrical","scene":"Now she plays the martyr. Why does he always come running to her, this grown man with no concept of self-care and half a brain gone missing? She asks to be let be like a woman who had no part in it, and the halo she puts on is purely for show."},{"label":"The Tell","mood":"knowing, exposed","scene":"The bridge flips the whole song. She likes her boys hard to get, likes her men incompetent, and says so out loud. \"I swear they choose me, I'm not choosing them\" is the line that gives her away. The innocent woman wanted this all along, and she almost laughs admitting it."}],"lines":[{"line":"You said your phone was broken, just forgot to charge it"},{"line":"Did you just say you're finished? Didn't know we started"},{"line":"Half your brain just ain't there"},{"line":"And I like my men all incompetent\nAnd I swear they choose me, I'm not choosing them"}],"texture":"A sunny, mid-tempo pop strut you can dance to, bright and major-key all the way through. The melody's so cheerful the insults slide down like a wink."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
FROM public.song s
WHERE s.spotify_id = $demosr$42UBPzRMh5yyz0EDPr6fr1$demosr$
  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

-- Drake — God's Plan
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$6DCZcSspjsKoFjzjrWoCdn$demosr$, $demosr$God's Plan$demosr$, ARRAY[$demosr$Drake$demosr$]::text[], ARRAY[$demosr$3TVXtAsR1Inumwj472S9r4$demosr$]::text[], ARRAY[$demosr$rap$demosr$, $demosr$hip-hop$demosr$, $demosr$rnb$demosr$]::text[], $demosr$Scorpion$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273f907de96b9a4fbc04accc0d5$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"a dead friend's name tatted on the arm","lens":"a roll call as armor","tension":"Guarded Gratitude","take":"Everybody's wishing bad things on him, and the answer he gives back isn't a clapback. It's a list of names. He's moving calm, even though keeping it peaceful is a struggle, and under that calm sits something darker. He doesn't want to die just so the world finally misses him, the way it only learns to love its artists once they're gone. So he counts the people who keep him here instead. His bed and his mama. The broskies. 40 and Oli, without whom there'd be no him. And Fif, gone since the fall, whose name he got tatted on his arm so it outlives them both. The loyalty is the armor. Whatever God's got planned, he can't do it on his own, and he says so plainly while he makes sure the north-side eats.","contradiction":"He doesn't want to die just for the world to finally miss him, yet he keeps circling back to how going down would let him go down a G-O-D.","arc":[{"label":"The Wishing","mood":"Guarded, watchful","scene":"He's moving calm and starting nothing, but he can feel the bad things people are wishing on him from every side. The calm is a struggle to hold. Already death is in his mouth — he hopes he's got brothers who outlive him, and he doesn't want to be missed only after he's gone."},{"label":"The Answer","mood":"Defiant, steady","scene":"God's plan, he says, like that settles it. He holds back, and sometimes he won't. The reply to all that hate isn't aimed back at anyone — it's making sure the north-side eats and that he goes down for something different. And still."},{"label":"The Roll Call","mood":"Tender, grateful","scene":"When she asks if he loves her, he only loves her partly. His bed and his mama come first, and he's sorry. Then he names the rest of the people holding him up — Fif tatted on his skin, 40 and Oli, the broskies he can't imagine never meeting. He can't do this on his own, and he doesn't pretend he could."}],"lines":[{"line":"Hope I got some brothers that outlive me"},{"line":"I make sure that north-side eat"},{"line":"I only love my bed and my mama, I'm sorry"},{"line":"Without 40, Oli, there'd be no me"}],"texture":"A slow, muted beat at a crawl, low-lit and sparse, the kind of bounce that keeps you nodding without ever brightening. The groove is there to dance to, but the color is drained out of it, the lift carrying more weight than it lets on."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
FROM public.song s
