  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

-- Bad Bunny — DtMF
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$3sK8wGT43QFpWrvNQsrQya$demosr$, $demosr$DtMF$demosr$, ARRAY[$demosr$Bad Bunny$demosr$]::text[], ARRAY[$demosr$4q3ewBCX7sLwd24euuV69X$demosr$]::text[], ARRAY[$demosr$latin$demosr$, $demosr$reggaeton$demosr$, $demosr$salsa$demosr$]::text[], $demosr$Debí Tirar Más Fotos$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b273bbd45c8d36e0e045ef640411$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"another pretty sunset over San Juan, and the ones who left","lens":"a homecoming as a goodbye","tension":"Aching Joy","take":"Home looks like everything he wanted. Another sunset over San Juan, dominó with his grandfather, the whole corillo wrecking the street. But every good thing here arrives already mourned. The hook is pure retroactive regret: he should have taken more photos of when he had her, given more kisses and hugs while he had the chance. So now he pulls everyone in for the photo before the next person leaves, and the prayer underneath it is small and scared — ojalá que los míos nunca se muden, please don't let my people move away. He swears to his grandfather he doesn't think about her, and the whole night calls him a liar. The drinking isn't a party so much as a way to stand inside the joy without it cutting him. Enjoy tonight, because nunca se sabe si nos queda poco.","contradiction":"He tells his grandfather over dominó that he doesn't think about her anymore, and every photo he wishes he'd taken says he still does.","arc":[{"label":"The Pretty Ache","mood":"wistful, longing","scene":"He watches another sunset over San Juan and enjoys all the things the ones who leave end up missing. Even here, home and content, he wants to go back to the last time he looked her in the eyes, to tell her the things he never told her and take the photos he never took."},{"label":"The Regret","mood":"aching, raw","scene":"It lands as a confession he keeps repeating to himself. He should have taken more photos of when he had her. He should have given more kisses and hugs the times he could. Then the prayer slips out, bigger than her now — that his people never move away, and if he gets drunk tonight, that someone helps him."},{"label":"The Party as Defense","mood":"drunk, willed joy","scene":"He spends the day with his grandfather, and when the old man asks if he still thinks about her, he lies and says no. Then it's off to Santurce to drink until they throw him out. He calls the whole crew in for one photo, métase to'l mundo, because you never know if little is left."},{"label":"What's Left","mood":"tender, grown","scene":"His brother Bernie has a son now and Jan has a daughter, and the movies and the chains stopped mattering. What's left is the stuff worth the trouble — el perreo, la salsa, la bomba y la plena. He ends right back at the same regret, only now he's asking Beno to help him through it."}],"lines":[{"line":"Disfrutando de todas esas cosas que extrañan los que se van"},{"line":"Debí tirar más fotos de cuando te tuve"},{"line":"Si me pregunta si aún pienso en ti, yo le digo que no"},{"line":"Vamo' a disfrutar, que nunca se sabe si nos queda poco"},{"line":"'Tamos pa' las cosa' que valgan la pena"}],"texture":"A reggaeton and salsa pulse built to move a whole street, except it sits down low and almost colorless, the saddest valence riding a beat you can still dance to. The most danceable kind of heavy."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
