-- Gracie Abrams — That's So True
INSERT INTO public.song (spotify_id, name, artists, artist_ids, genres, album_name, image_url, created_at, updated_at)
VALUES ($demosr$7ne4VBA60CxGM75vw0EYad$demosr$, $demosr$That's So True$demosr$, ARRAY[$demosr$Gracie Abrams$demosr$]::text[], ARRAY[$demosr$4tuJ0bMpJh08umKkEXKUI5$demosr$]::text[], ARRAY[$demosr$indie pop$demosr$, $demosr$folk$demosr$, $demosr$pop$demosr$]::text[], $demosr$The Secret of Us (Deluxe)$demosr$, $demosr$https://i.scdn.co/image/ab67616d0000b2731dac3694b3289cd903cb3acf$demosr$, now(), now())
ON CONFLICT (spotify_id) DO NOTHING;
INSERT INTO public.song_analysis (song_id, analysis, model, prompt_version, created_at, updated_at)
SELECT s.id, $demosr${"image":"saying you're fine from inside the coffin","lens":"contempt as a coffin","tension":"Spiteful Longing","take":"Every insult here is a place to lie down and play dead. She calls him an idiot, calls him \"just another dude,\" and the cooler she sounds the more you hear what it costs. The cruelty is real and so is the wound under it — \"I died when you started walking\" isn't a metaphor she's hiding, it's the thing the contempt was built to cover. She watches him with the new girl and can't decide whether she likes her or hates her, lands on \"I'm not that evolved, I'm sorry,\" and means both halves. The worst part is the recognition. \"Wait, I think I've been there too.\" She was once the cool girl on his couch making eyes across the room, so trashing the new one is trashing the version of herself he already replaced. Smiling through it all, yeah, that's her life. The smile and the coffin are the same gesture.","contradiction":"She swears it isn't her business and warns the new girl off him anyway, twice.","arc":[{"label":"The Cold Read","mood":"spiteful, fixated","scene":"She knows him too well to need words. She can read his mind, picture his dumb face whenever she wants, and she hates that she can. So she sharpens it into a verdict. \"You're an idiot, now I'm sure.\" Calling him stupid is easier than admitting he still lives behind her eyes, in a glass house she's stuck looking into from outside."},{"label":"The Catch","mood":"jealous, self-aware","scene":"Then she watches the new girl kick back on his couch and take her hair down, and the knife slips. \"Wait, I think I've been there too.\" She was the one making eyes across that room once, so every jab at the new girl lands on her own replaced self. She can't even hold a position. She likes her, hates her, says \"I'm not that evolved, I'm sorry,\" and the apology is half to the girl and half to herself."},{"label":"The Coffin","mood":"raw grief, bravado","scene":"The act drops all at once. \"Said that I was fine, said it from my coffin.\" Every cool line all night was spoken by someone playing dead so he wouldn't see the body. Then she sits up, takes out her earrings for a fight she won't win, and reaches for the armor again. \"You're just another dude.\" That's so true, and she almost believes it."}],"lines":[{"line":"Smiling through it all, yeah, that's my life"},{"line":"But I think I like her, she's so fun\nWait, I think I hate her, I'm not that evolved, I'm sorry"},{"line":"She's missing it, sad, sad boy"},{"line":"And she'll spend the night, catch me on your ceiling"}],"texture":"A bright, loud pop bounce at a brisk clip, more momentum than melancholy on the surface. The mood underneath runs darker than the beat lets on, so you catch yourself singing along to the cruelty."}$demosr$::jsonb, 'curated:landing-v17', 'curated', now(), now()
FROM public.song s
WHERE s.spotify_id = $demosr$7ne4VBA60CxGM75vw0EYad$demosr$
  AND NOT EXISTS (
    SELECT 1 FROM public.song_analysis a
    WHERE a.song_id = s.id AND a.model = 'curated:landing-v17'
  );

